  variants: {
    variant: {
      default: [
        "border-transparent",
        "bg-primary",
        "text-primary-foreground",
        "[a&]:hover:bg-primary/90",
      ],
      secondary: [
        "border-transparent",
        "bg-secondary",
        "text-secondary-foreground",
        "[a&]:hover:bg-secondary/90",
      ],
      destructive: [
        "border-transparent",
        "bg-destructive",
        "text-white",
        "focus-visible:ring-destructive/20",
        "dark:bg-destructive/60",
